import{_ as a,o as i,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/schrift009.jpg",n="/images/schrift010.jpg",p="/images/schrift011.jpg",f=JSON.parse('{"title":"Devanāgarī = देवनागरी","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift06.md","filePath":"lektionen/schrift06.md"}'),h={name:"lektionen/schrift06.md"};function o(c,e,u,l,g,d){return i(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="devanagari-देवनागरी" tabindex="-1">Devanāgarī = देवनागरी <a class="header-anchor" href="#devanagari-देवनागरी" aria-label="Permalink to &quot;Devanāgarī = देवनागरी&quot;">​</a></h1><h2 id="schriftubung-6" tabindex="-1">Schriftübung 6 <a class="header-anchor" href="#schriftubung-6" aria-label="Permalink to &quot;Schriftübung 6&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><p>Für jha ist auch folgende Form gebräuchlich:</p><p><img src="'+n+'" alt=""></p><p>In älteren Büchern, die in Calcutta gedruckt wurden, finden sich für jha auch die Formen:</p><p><img src="'+p+'" alt=""></p><h2 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h2><p>A) Schreiben Sie in Devanāgarī:</p><p>bhavati yudh dhenuḥ sādhavaḥ bhūmiḥ ḍhuḍhi ghaṭa ḍuḍhauke jhālā ḍhola ghoṣaṃ bhṛ jaghajhagāyamāno bhos jhāḍhāmalā bhogaḥ</p><p>B) Lesen und transliterieren Sie:</p><p>a) द ध त फ प न च ड ग क भ ब थ छ य ख झ</p><p>b) भट पद कड मठ थन खच् दध् दम छद् झग जड फट पथ बत छग पढ घट</p><p>c) गमक जगत् मथन धटक पठक दमथ धटक कपट भजक कथम् खजक पदक</p><p>d) छदनम् नटनम् कथनम् जनपद गमनम् पठनम् धनमद</p><p>e) व य र ल ब थ ख त</p><p>f) लव जल खर वद् झर बल वर पठ् लभ् यव थर लय झर रट् फल् रथ</p><p>g) तरल भयम् धवल जठर डमर नखर लगड चपल भवत् नयन वचर लटभ</p><p>h) यमवत् वयनम् तरलम् पदकमल कपटवचनम्</p><p>i)  ष ह स श प ड र ख</p><p>j) शर सह षट् वश हस् झष रस वष् शव सत् शठ खश कष शस् हय हर झष भव</p><p>k) सरल कलश जहत् वयस् शपथ समय वहल शलभ यशस् शरट् सफल सरस हरक परश रभस हतक</p><p>l)  दशरथ शकटम् सवयस् कलहम् शसनम् शतशस् जलचरस् नवदशकम् सहगमनम् कमलवदन दशशतम्</p>',24)])])}const _=a(h,[["render",o]]);export{f as __pageData,_ as default};
